38	  content: '';
39	  position: fixed;
40	  inset: 0;
41	  pointer-events: none;
42	  z-index: 9999;
43	  opacity: 0.015;
44	  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
45	}
46	
47	/* Section glow backgrounds */
48	.glow-bg {
49	  position: relative;
50	  background: var(--color-ocean-900);
51	}
52	.glow-bg::before {
53	  content: '';
54	  position: absolute;
55	  inset: 0;
56	  background:
57	    radial-gradient(ellipse 80% 60% at 50% 40%, rgba(17, 154, 158, 0.07) 0%, transparent 70%),
58	    radial-gradient(ellipse 50% 40% at 30% 70%, rgba(201, 169, 110, 0.04) 0%, transparent 60%);
59	  pointer-events: none;
60	}
61	
62	/* Subtle divider line */
63	.divider-line {
64	  height: 1px;
65	  background: linear-gradient(90deg, transparent, rgba(17, 154, 158, 0.15), transparent);
66	}
67	
68	/* Glass card base */
69	.glass-card {
70	  background: rgba(255, 255, 255, 0.02);
71	  border: 1px solid rgba(255, 255, 255, 0.05);
72	  border-radius: 16px;
73	  backdrop-filter: blur(4px);
74	  transition: all 0.35s cubic-bezier(0.4, 0, 0.2, 1);
75	}
76	.glass-card:hover {
77	  background: rgba(255, 255, 255, 0.04);
78	  border-color: rgba(17, 154, 158, 0.2);
79	  transform: translateY(-4px);
80	  box-shadow: 0 16px 48px rgba(0, 0, 0, 0.4);
81	}
82	
83	/* Branch content — hide raw markdown headings, use gradient separators */
84	.branch-content h2 {
85	  font-size: 0;
86	  line-height: 0;
87	  height: 0;
88	  margin: 0;
89	  padding: 0;
90	  overflow: hidden;
91	}
92	.branch-content h2::after {
93	  content: '';
94	  display: block;
95	  width: 40px;
96	  height: 1px;
97	  margin: 3rem 0 1.5rem;
98	  background: linear-gradient(90deg, var(--color-ocean-500), transparent);
99	  font-size: 0;
100	}
101	.branch-content p {
102	  margin-bottom: 1.25rem;
103	  line-height: 1.9;
104	  color: rgba(255, 255, 255, 0.55);
105	}
106	.branch-content ul {
107	  padding-left: 1.25rem;
108	  margin-bottom: 1.25rem;
109	}
110	.branch-content li {
111	  margin-bottom: 0.5rem;
112	  line-height: 1.8;
113	  color: rgba(255, 255, 255, 0.5);
114	}
115	.branch-content strong {
116	  color: rgba(255, 255, 255, 0.8);
117	  font-weight: 500;
118	}
119	
120	/* Superscript Citations */
121	sup {
122	  font-size: 10px;
123	  color: var(--color-ocean-400);
124	  font-weight: 600;
125	  margin-left: 2px;
126	  padding: 1px 4px;
127	  border-radius: 2px;
128	  background: rgba(17, 154, 158, 0.1);
129	  vertical-align: baseline;
130	  position: relative;
131	  top: -0.4em;
132	  cursor: help;
133	}
