1	---
2	import { getCollection } from 'astro:content';
3	import Base from '../../layouts/Base.astro';
4	import CTAButton from '../../components/CTAButton.astro';
5	import ComingSoon from '../../components/ComingSoon.astro';
6	import ResearchAccordion from '../../components/ResearchAccordion.astro';
7	import VerticalSpine from '../../components/VerticalSpine.astro';
8	import EmailGate from '../../components/EmailGate.astro';
9	import { config } from '../../data/hub.config';
10	
11	export async function getStaticPaths() {
12	  const branches = await getCollection('branches');
13	  return branches.map((branch) => ({
14	    params: { slug: branch.id.replace(/\.md$/, '') },
15	    props: { branch },
16	  }));
17	}
18	
19	const { branch } = Astro.props;
20	const { Content } = await branch.render();
21	const { title, emoji, hook, status, tone } = branch.data;
22	const ctaLabel = tone === 'soft' ? 'Explore gently' : 'Start with your water';
23	
24	const branchConfig = config.branches.find(b => b.slug === branch.id.replace(/\.md$/, ''));
25	const citationIds = branchConfig?.citationIds || [];
26	const branchGhlUrl = branchConfig?.ghlUrl || config.ghl.productUrl;
27	---
28	
29	<Base title={`${title} — Water`}>
30	  <VerticalSpine />
31	  <!-- Branch header — FREE (Layer 1) -->
32	  <section class="relative min-h-[60vh] flex flex-col items-center justify-center text-center px-6 py-24 glow-bg overflow-hidden">
33	    <div class="relative text-6xl mb-6">{emoji}</div>
34	    <h1 class="relative font-heading text-[clamp(40px,5vw,64px)] font-light text-white leading-[1.1] mb-6" style="text-shadow: 0 0 50px rgba(17,154,158,0.12);">
35	      {title}
36	    </h1>
37	    <p class="relative font-heading italic text-white/45 text-[clamp(18px,2.5vw,24px)] leading-relaxed max-w-2xl">
38	      {hook}
39	    </p>
40	  </section>
41	
42	  <!-- Deep content — GATED (Layer 2) -->
43	  <div class="divider-line"></div>
44	  <section class="py-16 px-6 bg-ocean-900">
45	    <div class="max-w-[640px] mx-auto">
46	      {status === 'placeholder' ? (
47	        <ComingSoon title={title} emoji={emoji} />
48	      ) : (
49	        <EmailGate preview={`Research-backed deep dive into ${title.toLowerCase()} — what it means, where water fits, and what the science shows.`}>
50	          <div class="branch-content text-[16px] leading-[1.9]">
51	            <Content />
52	          </div>
53	          <ResearchAccordion ids={citationIds} />
54	        </EmailGate>
55	      )}
56	    </div>
57	  </section>
