19	  function updateSpine() {
20	    if (!progress) return;
21	    
22	    const winScroll = document.body.scrollTop || document.documentElement.scrollTop;
23	    const height = document.documentElement.scrollHeight - document.documentElement.clientHeight;
24	    const scrolled = (winScroll / height) * 100;
25	    
26	    progress.style.height = scrolled + "%";
27	    
28	    if (winScroll > 50) {
29	      line?.classList.remove('opacity-0');
30	    } else {
31	      line?.classList.add('opacity-0');
32	    }
33	  }
34	
35	  let ticking = false;
36	  window.addEventListener('scroll', () => {
37	    if (!ticking) {
38	      requestAnimationFrame(() => {
39	        updateSpine();
40	        ticking = false;
41	      });
42	      ticking = true;
43	    }
44	  });
45	  window.addEventListener('resize', updateSpine);
